import React, { useState } from 'react';
import axios from 'axios';


const UpdateProfile: React.FC = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');

    // Presupunem că ID-ul utilizatorului și token-ul sunt stocate după login
    const userId = localStorage.getItem('userId'); // Exemplu: '1'
    const token = localStorage.getItem('token');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!userId) {
            alert('Trebuie să fii autentificat!');
            return;
        }

        try {
            await axios.put(`http://localhost:8080/api/users/${userId}`,
                {
                    username: username,
                    password: password
                },
                {
                    headers: {
                        'Authorization': `Bearer ${token}` // Trimitem token-ul pentru autorizare
                    }
                });
            alert('Profil actualizat cu succes!');
        } catch (error) {
            console.error('Eroare la actualizare:', error);
            alert('Eroare la actualizarea profilului!');
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <h2>Actualizează Datele</h2>
            <div>
                <label>Noul Username</label>
                <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} />
            </div>
            <div>
                <label>Noua Parolă</label>
                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} />
            </div>
            <button type="submit" className="update-button">Actualizează</button>
        </form>
    );
};

export default UpdateProfile;
